/**
 * Agent-memory sync — PostToolUse hook contribution.
 *
 * Replaces capellai's `.claude/hooks/append-memory-to-claudemd.py`
 * (ADR-013 Paso 8). Watches PostToolUse Write/Edit payloads. When the
 * tool target matches an agent-memory file path (Claude Code's
 * `~/.claude/projects/<slug>/memory/*.md`, excluding `MEMORY.md`), the
 * written content is appended to the project's agent-memory file inside
 * a managed section before the `<!-- Generated by Codi -->` marker, so
 * the new memory lives in the user-managed zone and survives
 * `codi generate`.
 *
 * **Multi-agent target detection** (ADR-013 multi-agent compatibility):
 * each call writes to EVERY agent-memory file present in the project:
 *   - `CLAUDE.md` if `CLAUDE.md` or `.claude/` exists (Claude Code)
 *   - `AGENTS.md` if `AGENTS.md` or `.codex/` exists (Codex)
 * Projects with both agents installed get the same memory entry written
 * to both files, so Claude Code and Codex sessions see the same
 * user-managed memory.
 *
 * Idempotent: a SHA256 of `(file_path + content)` is recorded in
 * `.codi/state/claudemd-memory-seen.txt`. Re-firing with the same
 * payload is a no-op for ALL targets (one fingerprint per source
 * memory write, regardless of how many target files receive it).
 *
 * Fail-open: errors print to stderr and never block the agent's tool
 * execution. The PostToolUse dispatcher in `agent-hooks.ts` calls
 * `runMemorySync()` AFTER the brain capture path runs, so the brain
 * always sees the event regardless of whether the .md append succeeds.
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { createHash } from "node:crypto";
import { PROJECT_DIR } from "../../../constants.js";

const CODI_MARKER = "<!-- Generated by Codi | Do not edit";
const SECTION_FENCE =
  "<!-- AGENT MEMORY CAPTURES — append-only, managed by codi hook post-tool-use -->";
const SECTION_END_FENCE = "<!-- /AGENT MEMORY CAPTURES -->";
const STATE_FILE_RELATIVE = `${PROJECT_DIR}/state/claudemd-memory-seen.txt`;

function isMemoryPath(path: string): boolean {
  if (!path.includes("/.claude/projects/")) return false;
  if (!path.includes("/memory/")) return false;
  if (!path.endsWith(".md")) return false;
  // MEMORY.md is the user's index file, not an individual memory entry.
  if (path.endsWith("/MEMORY.md")) return false;
  return true;
}

function fingerprintEntry(filePath: string, content: string): string {
  return createHash("sha256").update(filePath).update("\n").update(content).digest("hex");
}

function readSeenFingerprints(cwd: string): Set<string> {
  const stateFile = join(cwd, STATE_FILE_RELATIVE);
  if (!existsSync(stateFile)) return new Set();
  try {
    const raw = readFileSync(stateFile, "utf8");
    return new Set(
      raw
        .split("\n")
        .map((line) => line.trim())
        .filter((line) => line.length === 64),
    );
  } catch {
    return new Set();
  }
}

function recordSeenFingerprint(cwd: string, fingerprint: string): void {
  const stateFile = join(cwd, STATE_FILE_RELATIVE);
  try {
    mkdirSync(dirname(stateFile), { recursive: true });
    appendFileSync(stateFile, fingerprint + "\n", { encoding: "utf8" });
  } catch {
    // State write is non-critical; future runs will simply re-detect
    // and the dedup section below catches double-appends within a session.
  }
}

interface ParsedClaudeMd {
  pre: string;
  memorySectionLines: string[];
  rest: string;
}

function parseClaudeMd(content: string): ParsedClaudeMd {
  const sectionStart = content.indexOf(SECTION_FENCE);
  const sectionEnd = content.indexOf(SECTION_END_FENCE);
  const codiMarkerIdx = content.indexOf(CODI_MARKER);

  let pre = "";
  let memorySectionLines: string[] = [];
  let rest = "";

  if (sectionStart !== -1 && sectionEnd !== -1 && sectionEnd > sectionStart) {
    pre = content.slice(0, sectionStart);
    const sectionBody = content.slice(
      sectionStart + SECTION_FENCE.length,
      sectionEnd,
    );
    memorySectionLines = sectionBody.split("\n");
    rest = content.slice(sectionEnd + SECTION_END_FENCE.length);
  } else if (codiMarkerIdx !== -1) {
    pre = content.slice(0, codiMarkerIdx);
    rest = content.slice(codiMarkerIdx);
  } else {
    pre = content;
    rest = "";
  }

  return { pre, memorySectionLines, rest };
}

function formatEntry(filePath: string, content: string, isoDate: string): string {
  const base = filePath.split("/").pop() ?? filePath;
  return [
    "",
    `<!-- entry: ${base} @ ${isoDate} -->`,
    "---",
    content.trim(),
    "---",
    "",
  ].join("\n");
}

/**
 * Detect every agent-memory file present in the project. ADR-013
 * multi-agent compatibility: an entry written to one is written to all.
 *
 * Detection rules:
 *   CLAUDE.md → ship if either `CLAUDE.md` already exists OR `.claude/`
 *               exists (Claude Code-managed project).
 *   AGENTS.md → ship if either `AGENTS.md` already exists OR `.codex/`
 *               exists (Codex-managed project).
 *
 * A project with NEITHER directory NOR file gets nothing written
 * (graceful no-op — codi is installed but no agent has been wired yet).
 */
function detectMemoryTargets(cwd: string): string[] {
  const targets: string[] = [];
  const claudeMdExists = existsSync(join(cwd, "CLAUDE.md"));
  const claudeDirExists = existsSync(join(cwd, ".claude"));
  if (claudeMdExists || claudeDirExists) {
    targets.push(join(cwd, "CLAUDE.md"));
  }
  const agentsMdExists = existsSync(join(cwd, "AGENTS.md"));
  const codexDirExists = existsSync(join(cwd, ".codex"));
  if (agentsMdExists || codexDirExists) {
    targets.push(join(cwd, "AGENTS.md"));
  }
  return targets;
}

/**
 * Append a memory write to a single target file. Returns true on
 * success. Caller handles dedup fingerprint at the source-write level.
 */
function appendMemoryToFile(targetPath: string, entry: string): boolean {
  let existing = "";
  if (existsSync(targetPath)) {
    try {
      existing = readFileSync(targetPath, "utf8");
    } catch {
      return false;
    }
  }

  const parsed = parseClaudeMd(existing);

  let newSectionBody: string;
  if (parsed.memorySectionLines.length > 0) {
    newSectionBody = parsed.memorySectionLines.join("\n") + entry;
  } else {
    newSectionBody = "\n" + entry;
  }

  const newSection = `${SECTION_FENCE}${newSectionBody}${SECTION_END_FENCE}\n`;
  const next = parsed.pre + (parsed.pre.endsWith("\n") ? "" : "\n") + newSection + parsed.rest;

  try {
    writeFileSync(targetPath, next, { encoding: "utf8" });
    return true;
  } catch {
    return false;
  }
}

/**
 * Append a memory write to every agent-memory file in the project.
 * Idempotent at the SOURCE write level: calling twice with the same
 * `(filePath, content)` records the fingerprint once and is a no-op
 * for every target on the second call.
 *
 * Returns the count of target files modified.
 */
export function appendMemoryToAgentFiles(opts: {
  cwd: string;
  filePath: string;
  content: string;
}): number {
  if (!isMemoryPath(opts.filePath)) return 0;

  const fingerprint = fingerprintEntry(opts.filePath, opts.content);
  const seen = readSeenFingerprints(opts.cwd);
  if (seen.has(fingerprint)) return 0;

  const targets = detectMemoryTargets(opts.cwd);
  if (targets.length === 0) return 0;

  const isoDate = new Date().toISOString().replace("T", " ").slice(0, 19);
  const entry = formatEntry(opts.filePath, opts.content, isoDate);

  let modified = 0;
  for (const target of targets) {
    if (appendMemoryToFile(target, entry)) modified += 1;
  }
  if (modified > 0) {
    recordSeenFingerprint(opts.cwd, fingerprint);
  }
  return modified;
}

/**
 * PostToolUse entry point. Inspects the payload's tool input/response
 * for a memory-file write and forwards to `appendMemoryToAgentFiles`,
 * which writes to every agent-memory file present in the project
 * (CLAUDE.md and/or AGENTS.md per multi-agent target detection).
 */
export function runMemorySync(opts: {
  cwd: string;
  toolName: string;
  toolInput: Record<string, unknown>;
  enabled: boolean;
}): void {
  if (!opts.enabled) return;
  if (opts.toolName !== "Write" && opts.toolName !== "Edit") return;

  const filePath =
    typeof opts.toolInput["file_path"] === "string"
      ? opts.toolInput["file_path"]
      : typeof opts.toolInput["path"] === "string"
        ? opts.toolInput["path"]
        : undefined;
  if (typeof filePath !== "string") return;

  // For Edit, the payload contains `new_string`; for Write, `content`.
  const content =
    typeof opts.toolInput["content"] === "string"
      ? opts.toolInput["content"]
      : typeof opts.toolInput["new_string"] === "string"
        ? opts.toolInput["new_string"]
        : undefined;
  if (typeof content !== "string" || content.length === 0) return;

  try {
    appendMemoryToAgentFiles({ cwd: opts.cwd, filePath, content });
  } catch {
    // Fail-open per the dispatcher's contract.
  }
}
